import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"84. Workload","description":"","frontmatter":{"title":"84. Workload","eba":"Biomedical Engineers 2025-2028","topics":["hours","overtime","staffing","workload"]},"headers":[],"relativePath":"ebas/biomedical-engineers/classification-staffing/84-workload.md","filePath":"ebas/biomedical-engineers/classification-staffing/84-workload.md"}'),s={name:"ebas/biomedical-engineers/classification-staffing/84-workload.md"};function n(i,e,l,p,d,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_84-workload" tabindex="-1">84. Workload <a class="header-anchor" href="#_84-workload" aria-label="Permalink to &quot;84. Workload&quot;">​</a></h1><p><strong>84.1</strong> Purpose</p><p><strong>(a)</strong> The Employer acknowledges the benefits to both the organisation and the individual Employees gained through Employees having a balance between both their professional and family life.</p><p><strong>(b)</strong> The allocation of work must consider the Employee’s hours of work, health, safety and welfare.</p><p><strong>(c)</strong> The Employer is obliged by the OHS Act to provide a safe workplace. It is recognised that adequate staffing affects workload and is relevant to occupational health and safety in the workplace.</p><p><strong>84.2</strong> Reasonable Overtime</p><p><strong>(a)</strong> Work will be allocated so that an Employee does not work routinely beyond their ordinary hours of work to complete their duties.</p><p><strong>(b)</strong> However, the Employer may require the Employee to work reasonable overtime hours (in which case the provisions of <a href="/eba/ebas/biomedical-engineers/hours-of-work/46-overtime.html">clause 46</a> – Overtime will apply).</p><p><strong>(c)</strong> The Employee may refuse to work overtime hours if the request is unreasonable (see subclause 46.2).</p><p><strong>84.3</strong> Safe Staffing The Employer will ensure that it is sufficiently staffed and resourced so as to enable each Employee to:</p><p><strong>(a)</strong> perform all aspects of their role/position during their ordinary hours;</p><p><strong>(b)</strong> take rest intervals and meal breaks provided by this Agreement; and</p><p><strong>(c)</strong> take leave provided for by this Agreement and the NES.</p><p><strong>84.4</strong> Allocation of work The Employer will allocate work to each Employee so that they can perform all aspects of their position during their ordinary hours of work, including but not limited to:</p><p><strong>(a)</strong> administrative and clerical duties (data entry etc);</p><p><strong>(b)</strong> managerial/supervisory duties;</p><p><strong>(c)</strong> educational duties; and</p><p><strong>(d)</strong> attending meetings.</p><p><strong>84.5</strong> Workload concerns</p><p><strong>(a)</strong> If Employees are routinely performing aspects of their position beyond their ordinary hours of work, the Employer will consult with Employees to determine whether they consider their workload to be unreasonable.</p><p><strong>(b)</strong> In the event an individual Employee, or group of Employees, believes their workload is unreasonable, they may make a written request for a workload review:</p><p><strong>(i)</strong> following consultation with the Employer pursuant to subclause 84.5(a); or</p><p><strong>(ii)</strong> at any time; which sets out details of the Employee/s workload and the reasons why the workload is considered unreasonable.</p><p><strong>(c)</strong> The Employer will meet with the Employee/s to discuss the request as soon as practicable and within 21 days of the written request.</p><p><strong>(d)</strong> The Employer and Employee/s will do all that is reasonable to resolve the workload issue. In doing so, the Employer will have regard to the allocation of work requirements at subclause 84.4.</p><p><strong>(e)</strong> If, following a meeting at subclause 84.5(c), the workload issue is not resolved, the Employee/s or Employer may refer it to the dispute resolution procedure in this Agreement (<a href="/eba/ebas/allied-health/consultation-disputes/14-dispute-resolution-procedure.html">clause 14</a>).</p>',26)])])}const u=o(s,[["render",n]]);export{c as __pageData,u as default};
